
CREATE PROCEDURE AX2009.usp_Merge_SALESTABLE_OrdiniCliente
AS
BEGIN
SET NOCOUNT ON;

IF OBJECT_ID('AX2009.SALESTABLE_OrdiniCliente', N'U') IS NULL
BEGIN
    EXEC AX2009.usp_Create_SALESTABLE_OrdiniCliente;
    EXEC AX2009.usp_AddIndexes_SALESTABLE_OrdiniCliente;
END;

MERGE INTO AX2009.SALESTABLE_OrdiniCliente AS TGT
USING AX2009.SALESTABLE_OrdiniClienteView (nolock) AS SRC
ON SRC.DATAAREAID = TGT.DATAAREAID AND SRC.SALESID = TGT.SALESID
WHEN MATCHED AND (TGT.CUSTACCOUNT <> SRC.CUSTACCOUNT OR TGT.INVOICEACCOUNT <> SRC.INVOICEACCOUNT OR TGT.PURCHORDERFORMNUM <> SRC.PURCHORDERFORMNUM OR TGT.SALESGROUP <> SRC.SALESGROUP OR TGT.DOCUMENTSTATUS <> SRC.DOCUMENTSTATUS OR TGT.INTERCOMPANYORIGINALSALESID <> SRC.INTERCOMPANYORIGINALSALESID OR TGT.PAYMENT <> SRC.PAYMENT OR TGT.CASHDISC <> SRC.CASHDISC OR TGT.INTERCOMPANYORIGINALCUSTACCO22 <> SRC.INTERCOMPANYORIGINALCUSTACCO22 OR TGT.CUSTOMERREF <> SRC.CUSTOMERREF OR TGT.DLVTERM <> SRC.DLVTERM OR TGT.DLVMODE <> SRC.DLVMODE OR TGT.SALESSTATUS <> SRC.SALESSTATUS OR TGT.SALESTYPE <> SRC.SALESTYPE OR TGT.SALESPOOLID <> SRC.SALESPOOLID OR TGT.INTERCOMPANYDIRECTDELIVERY <> SRC.INTERCOMPANYDIRECTDELIVERY OR TGT.INTERCOMPANYDIRECTDELIVERYORIG <> SRC.INTERCOMPANYDIRECTDELIVERYORIG OR TGT.DELIVERYZIPCODE <> SRC.DELIVERYZIPCODE OR TGT.DELIVERYCOUNTY <> SRC.DELIVERYCOUNTY OR TGT.DELIVERYCOUNTRYREGIONID <> SRC.DELIVERYCOUNTRYREGIONID OR TGT.DELIVERYSTATE <> SRC.DELIVERYSTATE OR TGT.INTERCOMPANYORIGIN <> SRC.INTERCOMPANYORIGIN OR TGT.RETURNITEMNUM <> SRC.RETURNITEMNUM OR TGT.INVENTLOCATIONID <> SRC.INVENTLOCATIONID OR TGT.PAYMMODE <> SRC.PAYMMODE OR TGT.DELIVERYCITY <> SRC.DELIVERYCITY OR TGT.INTERCOMPANYCOMPANYID <> SRC.INTERCOMPANYCOMPANYID OR TGT.INTERCOMPANYPURCHID <> SRC.INTERCOMPANYPURCHID OR TGT.INTERCOMPANYORDER <> SRC.INTERCOMPANYORDER OR TGT.DLVREASON <> SRC.DLVREASON OR TGT.RECEIPTDATEREQUESTED <> SRC.RECEIPTDATEREQUESTED OR TGT.RECEIPTDATECONFIRMED <> SRC.RECEIPTDATECONFIRMED OR TGT.SHIPPINGDATEREQUESTED <> SRC.SHIPPINGDATEREQUESTED OR TGT.SHIPPINGDATECONFIRMED <> SRC.SHIPPINGDATECONFIRMED OR TGT.INVENTSITEID <> SRC.INVENTSITEID OR TGT.NPOCONFIRMBLOCKED <> SRC.NPOCONFIRMBLOCKED OR TGT.NPODATEDLVCUSTREQUEST <> SRC.NPODATEDLVCUSTREQUEST OR TGT.NPOCREDITBLOCKED <> SRC.NPOCREDITBLOCKED OR TGT.CREATEDDATETIME <> SRC.CREATEDDATETIME OR TGT.CREATEDBY <> SRC.CREATEDBY OR TGT.NPOWEEKRECEIPTDATECONFIRMED <> SRC.NPOWEEKRECEIPTDATECONFIRMED OR TGT.NPOWEEKSHIPPINGDATECONFIRMED <> SRC.NPOWEEKSHIPPINGDATECONFIRMED OR TGT.NPOPROJECTCODE <> SRC.NPOPROJECTCODE OR TGT.NPOPURCHIDAS400 <> SRC.NPOPURCHIDAS400 OR TGT.NPOSALESIDAS400 <> SRC.NPOSALESIDAS400 OR TGT.NPORECEIVEDFROMAS400 <> SRC.NPORECEIVEDFROMAS400 OR TGT.NPOPROJECTCUSTACCOUNT <> SRC.NPOPROJECTCUSTACCOUNT OR TGT.NPOSALESWEBNUM <> SRC.NPOSALESWEBNUM OR TGT.NPODLVDATEFORCING <> SRC.NPODLVDATEFORCING OR TGT.NPODLVDATEFORCINGSTATUS <> SRC.NPODLVDATEFORCINGSTATUS OR TGT.NPORETURNDISPOSITIONCODEID <> SRC.NPORETURNDISPOSITIONCODEID OR TGT.NCEREINSTATEMENTMATERIAL <> SRC.NCEREINSTATEMENTMATERIAL OR TGT.METACQUISITIONDATE <> SRC.METACQUISITIONDATE OR TGT.METSDICUP <> SRC.METSDICUP OR TGT.METSDICIG <> SRC.METSDICIG OR TGT.METDELIVERYDATEVERIFICATION <> SRC.METDELIVERYDATEVERIFICATION OR TGT.CURRENCYCODE <> SRC.CURRENCYCODE)
  THEN UPDATE SET TGT.CUSTACCOUNT = SRC.CUSTACCOUNT, TGT.INVOICEACCOUNT = SRC.INVOICEACCOUNT, TGT.PURCHORDERFORMNUM = SRC.PURCHORDERFORMNUM, TGT.SALESGROUP = SRC.SALESGROUP, TGT.DOCUMENTSTATUS = SRC.DOCUMENTSTATUS, TGT.INTERCOMPANYORIGINALSALESID = SRC.INTERCOMPANYORIGINALSALESID, TGT.PAYMENT = SRC.PAYMENT, TGT.CASHDISC = SRC.CASHDISC, TGT.INTERCOMPANYORIGINALCUSTACCO22 = SRC.INTERCOMPANYORIGINALCUSTACCO22, TGT.CUSTOMERREF = SRC.CUSTOMERREF, TGT.DLVTERM = SRC.DLVTERM, TGT.DLVMODE = SRC.DLVMODE, TGT.SALESSTATUS = SRC.SALESSTATUS, TGT.SALESTYPE = SRC.SALESTYPE, TGT.SALESPOOLID = SRC.SALESPOOLID, TGT.INTERCOMPANYDIRECTDELIVERY = SRC.INTERCOMPANYDIRECTDELIVERY, TGT.INTERCOMPANYDIRECTDELIVERYORIG = SRC.INTERCOMPANYDIRECTDELIVERYORIG, TGT.DELIVERYZIPCODE = SRC.DELIVERYZIPCODE, TGT.DELIVERYCOUNTY = SRC.DELIVERYCOUNTY, TGT.DELIVERYCOUNTRYREGIONID = SRC.DELIVERYCOUNTRYREGIONID, TGT.DELIVERYSTATE = SRC.DELIVERYSTATE, TGT.INTERCOMPANYORIGIN = SRC.INTERCOMPANYORIGIN, TGT.RETURNITEMNUM = SRC.RETURNITEMNUM, TGT.INVENTLOCATIONID = SRC.INVENTLOCATIONID, TGT.PAYMMODE = SRC.PAYMMODE, TGT.DELIVERYCITY = SRC.DELIVERYCITY, TGT.INTERCOMPANYCOMPANYID = SRC.INTERCOMPANYCOMPANYID, TGT.INTERCOMPANYPURCHID = SRC.INTERCOMPANYPURCHID, TGT.INTERCOMPANYORDER = SRC.INTERCOMPANYORDER, TGT.DLVREASON = SRC.DLVREASON, TGT.RECEIPTDATEREQUESTED = SRC.RECEIPTDATEREQUESTED, TGT.RECEIPTDATECONFIRMED = SRC.RECEIPTDATECONFIRMED, TGT.SHIPPINGDATEREQUESTED = SRC.SHIPPINGDATEREQUESTED, TGT.SHIPPINGDATECONFIRMED = SRC.SHIPPINGDATECONFIRMED, TGT.INVENTSITEID = SRC.INVENTSITEID, TGT.NPOCONFIRMBLOCKED = SRC.NPOCONFIRMBLOCKED, TGT.NPODATEDLVCUSTREQUEST = SRC.NPODATEDLVCUSTREQUEST, TGT.NPOCREDITBLOCKED = SRC.NPOCREDITBLOCKED, TGT.CREATEDDATETIME = SRC.CREATEDDATETIME, TGT.CREATEDBY = SRC.CREATEDBY, TGT.NPOWEEKRECEIPTDATECONFIRMED = SRC.NPOWEEKRECEIPTDATECONFIRMED, TGT.NPOWEEKSHIPPINGDATECONFIRMED = SRC.NPOWEEKSHIPPINGDATECONFIRMED, TGT.NPOPROJECTCODE = SRC.NPOPROJECTCODE, TGT.NPOPURCHIDAS400 = SRC.NPOPURCHIDAS400, TGT.NPOSALESIDAS400 = SRC.NPOSALESIDAS400, TGT.NPORECEIVEDFROMAS400 = SRC.NPORECEIVEDFROMAS400, TGT.NPOPROJECTCUSTACCOUNT = SRC.NPOPROJECTCUSTACCOUNT, TGT.NPOSALESWEBNUM = SRC.NPOSALESWEBNUM, TGT.NPODLVDATEFORCING = SRC.NPODLVDATEFORCING, TGT.NPODLVDATEFORCINGSTATUS = SRC.NPODLVDATEFORCINGSTATUS, TGT.NPORETURNDISPOSITIONCODEID = SRC.NPORETURNDISPOSITIONCODEID, TGT.NCEREINSTATEMENTMATERIAL = SRC.NCEREINSTATEMENTMATERIAL, TGT.METACQUISITIONDATE = SRC.METACQUISITIONDATE, TGT.METSDICUP = SRC.METSDICUP, TGT.METSDICIG = SRC.METSDICIG, TGT.METDELIVERYDATEVERIFICATION = SRC.METDELIVERYDATEVERIFICATION, TGT.CURRENCYCODE = SRC.CURRENCYCODE
WHEN NOT MATCHED
  THEN INSERT VALUES (DATAAREAID, SALESID, RECID, CUSTACCOUNT, INVOICEACCOUNT, PURCHORDERFORMNUM, SALESGROUP, DOCUMENTSTATUS, INTERCOMPANYORIGINALSALESID, PAYMENT, CASHDISC, INTERCOMPANYORIGINALCUSTACCO22, CUSTOMERREF, DLVTERM, DLVMODE, SALESSTATUS, SALESTYPE, SALESPOOLID, INTERCOMPANYDIRECTDELIVERY, INTERCOMPANYDIRECTDELIVERYORIG, DELIVERYZIPCODE, DELIVERYCOUNTY, DELIVERYCOUNTRYREGIONID, DELIVERYSTATE, INTERCOMPANYORIGIN, RETURNITEMNUM, INVENTLOCATIONID, PAYMMODE, DELIVERYCITY, INTERCOMPANYCOMPANYID, INTERCOMPANYPURCHID, INTERCOMPANYORDER, DLVREASON, RECEIPTDATEREQUESTED, RECEIPTDATECONFIRMED, SHIPPINGDATEREQUESTED, SHIPPINGDATECONFIRMED, INVENTSITEID, NPOCONFIRMBLOCKED, NPODATEDLVCUSTREQUEST, NPOCREDITBLOCKED, CREATEDDATETIME, CREATEDBY, NPOWEEKRECEIPTDATECONFIRMED, NPOWEEKSHIPPINGDATECONFIRMED, NPOPROJECTCODE, NPOPURCHIDAS400, NPOSALESIDAS400, NPORECEIVEDFROMAS400, NPOPROJECTCUSTACCOUNT, NPOSALESWEBNUM, NPODLVDATEFORCING, NPODLVDATEFORCINGSTATUS, NPORETURNDISPOSITIONCODEID, NCEREINSTATEMENTMATERIAL, METACQUISITIONDATE, METSDICUP, METSDICIG, METDELIVERYDATEVERIFICATION, CURRENCYCODE)
WHEN NOT MATCHED BY SOURCE
  THEN DELETE
OUTPUT
    CURRENT_TIMESTAMP AS merge_datetime,
    $action AS merge_action,
    'AX2009.SALESTABLE_OrdiniCliente' AS full_olap_table_name,
    'DATAAREAID = ' + CAST(COALESCE(inserted.DATAAREAID, deleted.DATAAREAID) AS NVARCHAR) + ' - ' + 'SALESID = ' + CAST(COALESCE(inserted.SALESID, deleted.SALESID) AS NVARCHAR) AS primary_key_description
INTO audit.merge_log_details;

END;
GO

